var langs = ['es', 'zh', 'vi', 'tl'];
var created = 0;
var updated = 0;
var errors = 0;

for (var tableName in tables) {
    var fields = tables[tableName];
    for (var fieldName in fields) {
        var trans = fields[fieldName];
        for (var li = 0; li < langs.length; li++) {
            var lang = langs[li];
            var label = trans[lang];
            if (!label) continue;

            try {
                // Check if record already exists
                var gr = new GlideRecord('sys_documentation');
                gr.addQuery('name', tableName);
                gr.addQuery('element', fieldName);
                gr.addQuery('language', lang);
                gr.query();

                if (gr.next()) {
                    gr.label = label;
                    gr.update();
                    updated++;
                } else {
                    gr.initialize();
                    gr.name = tableName;
                    gr.element = fieldName;
                    gr.language = lang;
                    gr.label = label;
                    gr.insert();
                    created++;
                }
            } catch (e) {
                gs.error('Translation error: ' + tableName + '.' + fieldName + ' [' + lang + ']: ' + e);
                errors++;
            }
        }
    }
}

gs.info('SVEM Translation Complete: ' + created + ' created, ' + updated + ' updated, ' + errors + ' errors');
gs.info('Total fields: ' + (created + updated) + ' across ' + langs.length + ' languages');
